import requests
import pandas as pd
from io import StringIO

LIPIDMAPS_URL = "https://www.lipidmaps.org/ms/rest/ms_search/"

def _get_num_matches(db, mzStr, adducts, tolerance=0.001):
    """Return the number of matches for the selected database and parameters."""
    # Filter invalid lines: keep only lines that can be parsed as float
    lines = mzStr.splitlines()
    valid_lines = []
    for line in lines:
        line = line.strip()
        if line == '':
            continue
        try:
            float(line)
            valid_lines.append(line)
        except ValueError:
            continue
    # Reconstruct the m/z string with only valid numeric values
    filtered_mzStr = '\n'.join(valid_lines)

    if not valid_lines:
        return 0

    # Prepare multipart form data using files parameter
    files = {'file': ('file.txt', StringIO(filtered_mzStr), 'text/plain')}
    data = {
        'CHOICE': db,
        'ion': adducts,
        'tol': str(tolerance),
        'sort': 'DELTA'
    }
    try:
        response = requests.post(LIPIDMAPS_URL, data=data, files=files)
    except requests.exceptions.RequestException:
        raise Exception(
            'Connection error with the database. Please check your network and try again after a few minutes.'
        )
    if len(response.text) == 0:
        return 0
    else:
        matches = pd.read_csv(StringIO(response.text), sep='\t', engine='python', index_col=False)
        if matches.empty:
            return 0
        else:
            try:
                unique_masses = matches['Input Mass'].unique()
            except KeyError:
                unique_masses = matches.iloc[:, 0].unique()
            return len(unique_masses)

def main():
    db = 'GLYCOLIPIDS'
    mz_values = '100.0\nabc\n200.0\n12.3.4\n300.0\n'
    adducts = 'M+H,M+Na'
    tolerance = 0.01

    num_matches = _get_num_matches(db, mz_values, adducts, tolerance)

    print(f'Number of unique m/z matches: {num_matches}')

if __name__ == '__main__':
    main()
